import type { IMarketTokenChart } from '@onekeyhq/shared/types/market';

import type {
  BusinessDay,
  ChartOptions,
  IChartApi,
  ISeriesApi,
  SeriesDefinition,
  UTCTimestamp,
} from 'lightweight-charts';

type IDeepPartial<T> = {
  [P in keyof T]?: T[P] extends (infer U)[]
    ? IDeepPartial<U>[]
    : T[P] extends readonly (infer X)[]
      ? readonly IDeepPartial<X>[]
      : IDeepPartial<T[P]>;
};

// type IPriceNumber = number;
// type ITimeNumber = number;

export type IOnHoverFunction = ({
  time,
  price,
}: {
  time?: UTCTimestamp | BusinessDay | Date | string;
  price?: number | string;
}) => void;
export interface IChartViewProps {
  data: IMarketTokenChart;
  onHover: IOnHoverFunction;
  height: number;
  isFetching: boolean;
}

export interface IChartViewAdapterProps extends IChartViewProps {
  lineColor: string;
  topColor: string;
  bottomColor: string;
}

export interface IOnekeyChartApi extends IChartApi {
  // eslint-disable-next-line camelcase
  _onekey_series?: ISeriesApi<'Area'>;
  // eslint-disable-next-line camelcase
  _onekey_areaSeriesDefinition?: SeriesDefinition<'Area'>;
}

function getSeriesValue(seriesData: unknown): number | undefined {
  if (seriesData && typeof seriesData === 'object' && 'value' in seriesData) {
    const value = seriesData.value;
    return typeof value === 'number' ? value : Number(value);
  }
  return undefined;
}

export function createChartDom(
  createChartFunc: (
    container: HTMLElement,
    options?: IDeepPartial<ChartOptions>,
  ) => IChartApi,
  areaSeriesDefinition: SeriesDefinition<'Area'>,
  domNode: HTMLElement,
  onHover: IOnHoverFunction,
  height: number,
  textColor?: string,
) {
  const chart = createChartFunc(domNode, {
    height,
    layout: {
      background: {
        color: 'transparent',
      },
      textColor,
    },
    crosshair: {
      vertLine: {
        visible: false,
        labelVisible: false,
      },
      horzLine: {
        visible: false,
        labelVisible: false,
      },
    },
    grid: {
      vertLines: { visible: false },
      horzLines: { visible: false },
    },
    timeScale: {
      visible: true,
      fixLeftEdge: true,
      fixRightEdge: true,
      lockVisibleTimeRangeOnResize: true,
      borderVisible: false,
      timeVisible: false,
      secondsVisible: false,
      tickMarkFormatter: (time: UTCTimestamp | BusinessDay) => {
        const date = new Date((time as number) * 1000);
        const month = String(date.getMonth() + 1).padStart(2, '0');
        const day = String(date.getDate()).padStart(2, '0');
        return `${month}/${day}`;
      },
    },
    rightPriceScale: {
      visible: false,
    },
    handleScale: {
      pinch: false,
      mouseWheel: false,
    },
  });
  const handleResize = () => {
    chart.applyOptions({ width: domNode.clientWidth });
  };
  chart.subscribeCrosshairMove(({ seriesData, time }) => {
    onHover({ time, price: getSeriesValue(seriesData.values().next().value) });
  });
  chart.timeScale().fitContent();
  window.addEventListener('resize', handleResize);
  // @ts-ignore
  globalThis._onekey_chart = chart;
  (chart as IOnekeyChartApi)._onekey_areaSeriesDefinition =
    areaSeriesDefinition;
  return { chart, handleResize };
}

export function updateChartDom({
  chart,
  lineColor,
  topColor,
  bottomColor,
  data,
}: {
  chart: IOnekeyChartApi;
  lineColor: string;
  topColor: string;
  bottomColor: string;
  data: IMarketTokenChart;
}) {
  const formattedData = (data as [UTCTimestamp, number][]).map(
    ([time, value]) => ({
      time,
      value,
    }),
  );
  if (!chart._onekey_series) {
    const areaSeriesDefinition = chart._onekey_areaSeriesDefinition;
    if (!areaSeriesDefinition) {
      return;
    }
    const newSeries = chart.addSeries(areaSeriesDefinition, {
      lineColor,
      topColor,
      bottomColor,
      lineWidth: 2,
      priceLineVisible: false,
      lastValueVisible: false,
      crosshairMarkerVisible: true,
      crosshairMarkerRadius: 4,
      crosshairMarkerBorderColor: lineColor,
      crosshairMarkerBackgroundColor: '#FFFFFF',
    });
    newSeries.setData(formattedData);
    chart._onekey_series = newSeries;
    return;
  }
  const series = chart._onekey_series;
  series.applyOptions({ lineColor, topColor, bottomColor });
  series.setData(formattedData);

  if (data.length > 2) {
    chart
      .timeScale()
      // https://github.com/tradingview/lightweight-charts/issues/1015
      .setVisibleLogicalRange({ from: 0.4, to: data.length - 1.4 });
  }
}

export type IPriceApiProps = {
  networkId: string;
  contract?: string;
  'vs_currency'?: string;
  days: string;
  points?: string;
};
